import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"88. Hours Of Work","description":"","frontmatter":{"title":"88. Hours Of Work","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","rosters","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/88-hours-of-work.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/88-hours-of-work.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/88-hours-of-work.md"};function s(i,e,l,h,p,m){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_88-hours-of-work" tabindex="-1">88. Hours Of Work <a class="header-anchor" href="#_88-hours-of-work" aria-label="Permalink to &quot;88. Hours Of Work&quot;">​</a></h1><p><strong>88.1</strong> A full time Employee will work an average of 152 hours per four-week period.</p><p><strong>88.2</strong> The roster for full-time Employees and part-time Employees in bed-based services and CAT teams (however so titled) will comprise minimum shift lengths of:</p><p><strong>(a)</strong> 8-hour day shift</p><p><strong>(b)</strong> 8-hour evening shift; and</p><p><strong>(c)</strong> 10-hour night shift. If required, discussions may take place at the local level between Employers and Employees and their unions to consider the application of this roster configuration to part-time Employees in non-bed based and CAT services.</p><p><strong>(d)</strong> By mutual Agreement, a 12 Hour Shift Agreement in accordance with a 12-hour shift agreement under <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/90C-proposals-to-vary-specific-matters.html">clause 90C</a>.</p><p><strong>88.3</strong> Accrued Day Off See <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/97-accrued-days-off.html">clause 97</a> – Accrued Day Off</p><p><strong>88.4</strong> Alterations to ordinary hours of work</p><p><strong>(a)</strong> The obligations as they apply to a particular Employer under sub-clauses 88.1 to</p><p><strong>88.2</strong> may be varied by agreement between the Employer and the affected Employee/s for the following reasons:</p><p><strong>(i)</strong> the majority of Employees seek shifts that are contrary to the 8:8:10 roster described in sub-clause 88.2 above; or</p><p><strong>(ii)</strong> to allow for the continuation of current arrangements with respect to &#39;hours of work&#39;; or</p><p><strong>(iii)</strong> in accordance with an individual flexibility agreement or flexible working arrangement.</p><p><strong>(b)</strong> Arrangements adopted in accordance with sub-clause 88.4(a)(i) or 88.4(a)(ii) above must not result, on balance, in a reduction in the overall terms and conditions of employment of the Employee to whom the proposed arrangements would apply.</p><p><strong>(c)</strong> Any agreement under this clause will be recorded in writing and copies shall be provided to Employees to whom the arrangements apply.</p><p><strong>88.5</strong> Additional shifts above staffing profile Additional shifts, above the existing staffing allocation, to meet specific treatment or program requirements may be met by shifts of up to 8 hours (10 hours night duty), but not less than 4 hours. Such shifts are not for the purpose of increasing the available staffing to meet ongoing escalated demand that continues beyond the end of the shift.</p><p><strong>88.6</strong> 12 Hour Shift Agreement</p><p><strong>(a)</strong> A 12 Hour Shift agreement that commences after this Agreement comes into operation will be implemented in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/90C-proposals-to-vary-specific-matters.html">clause 90C</a> (Implementation of a non-complying proposal) of this Agreement.</p><p><strong>(b)</strong> Any 12-hour shift trial or agreement must allow, as a minimum, for 2 meal breaks per 12-hour shift - one unpaid 30 minute meal break and one 20 minute paid meal break and three 10 minute paid tea breaks.</p><p><strong>(c)</strong> A 12-hour shift trial or agreement may be terminated either:</p><p><strong>(i)</strong> in the manner provided in the shift trial or agreement; or</p><p><strong>(ii)</strong> in the case of the Employer, following consultation in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> of this Agreement (Consultation) and, where relevant, <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.html">clause 20</a> (Redundancy and Associated Entitlements).</p>',23)])])}const u=t(n,[["render",s]]);export{f as __pageData,u as default};
